import React from 'react';

import { useSaveCurrencyMutation } from '@/features/internationalization/hooks/useInternationalizationMutations';
import type { CurrencyOption } from '@/shared/contracts/internationalization';
import { useToast } from '@/shared/ui/primitives.public';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';

interface CurrencyFormState {
  code: string;
  name: string;
  symbol: string;
}

interface UseCurrencyFormProps {
  currency?: CurrencyOption | null;
}

interface UseCurrencyFormReturn {
  form: CurrencyFormState;
  setForm: React.Dispatch<React.SetStateAction<CurrencyFormState>>;
  saveMutation: ReturnType<typeof useSaveCurrencyMutation>;
  handleSubmit: () => Promise<void>;
}

export function useCurrencyForm({ currency }: UseCurrencyFormProps): UseCurrencyFormReturn {
  const [form, setForm] = React.useState<CurrencyFormState>({
    code: '',
    name: '',
    symbol: '',
  });
  const { toast } = useToast();
  const saveMutation = useSaveCurrencyMutation();

  React.useEffect(() => {
    if (currency) {
      setForm({
        code: currency.code,
        name: currency.name,
        symbol: currency.symbol ?? '',
      });
    } else {
      setForm({ code: 'PLN', name: 'Polish Zloty', symbol: 'zł' });
    }
  }, [currency]);

  const handleSubmit = async (): Promise<void> => {
    if (!form.code.trim() || !form.name.trim()) {
      toast('Required fields missing.', { variant: 'error' });
      return;
    }

    try {
      const payload: { id?: string; data: { code: string; name: string; symbol: string } } = {
        data: {
          code: form.code.trim().toUpperCase(),
          name: form.name.trim(),
          symbol: form.symbol.trim(),
        },
      };
      if (currency?.id) {
        payload.id = currency.id;
      }

      await saveMutation.mutateAsync(payload);

      toast('Currency saved.', { variant: 'success' });
    } catch (err) {
      logClientCatch(err, {
        source: 'CurrencyModal',
        action: 'saveCurrency',
        currencyId: currency?.id,
      });
      toast('Failed to save currency.', { variant: 'error' });
    }
  };

  return {
    form,
    setForm,
    saveMutation,
    handleSubmit,
  };
}

'use client';

import React from 'react';

import {
  useInternationalizationActions,
  useInternationalizationData,
  useInternationalizationUi,
} from '@/features/internationalization/context/InternationalizationContext';
import { SettingsPanelBuilder } from '@/shared/ui/templates/SettingsPanelBuilder';
import type { SettingsPanelField } from '@/shared/contracts/ui/settings';

import { useLanguageForm } from './hooks/useLanguageForm';
import { renderSelectionChecklistGrid } from '../shared/renderSelectionChecklistGrid';

type LanguageFormState = {
  code: string;
  name: string;
  nativeName: string;
};

export function LanguageModal(): React.JSX.Element | null {
  const { isLanguageModalOpen, activeLanguage } = useInternationalizationUi();
  const { handleCloseLanguageModal } = useInternationalizationActions();
  const { filteredCountries: countries } = useInternationalizationData();

  const { form, setForm, selectedCountryIds, toggleCountry, isSaving, handleSubmit } =
    useLanguageForm();

  if (!isLanguageModalOpen) return null;

  const handleSaveClick = async (): Promise<void> => {
    await handleSubmit();
    handleCloseLanguageModal();
  };

  const fields: SettingsPanelField<LanguageFormState>[] = [
    {
      key: 'code',
      label: 'Code',
      type: 'text',
      placeholder: 'e.g. EN',
      required: true,
    },
    {
      key: 'name',
      label: 'Name',
      type: 'text',
      placeholder: 'e.g. English',
      required: true,
    },
    {
      key: 'nativeName',
      label: 'Native Name',
      type: 'text',
      placeholder: 'e.g. English',
      required: true,
    },
    {
      key: 'name', // Using existing key for custom field as key is required
      label: 'Associated Countries',
      type: 'custom',
      render: () =>
        renderSelectionChecklistGrid({
          className: 'mt-2',
          items: countries.map((country) => ({
            id: country.id,
            label: `${country.name} (${country.code})`,
          })),
          selectedIds: selectedCountryIds,
          onToggle: toggleCountry,
          emptyMessage: 'No countries available.',
        }),
    },
  ];

  const handleChange = (values: Partial<LanguageFormState>) => {
    if (values.code) {
      values.code = values.code.toUpperCase();
    }
    setForm((prev) => ({ ...prev, ...values }));
  };

  return (
    <SettingsPanelBuilder
      open={isLanguageModalOpen}
      onClose={handleCloseLanguageModal}
      title={activeLanguage ? 'Edit Language' : 'Add Language'}
      onSave={handleSaveClick}
      isSaving={isSaving}
      fields={fields}
      values={form}
      onChange={handleChange}
      size='md'
    />
  );
}

'use client';

import React from 'react';

import { useInternationalizationUi } from '@/features/internationalization/context/InternationalizationContext';
import { useSaveLanguageMutation } from '@/features/internationalization/hooks/useInternationalizationMutations';
import { useToast } from '@/shared/ui/primitives.public';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


type UseLanguageFormResult = {
  form: {
    code: string;
    name: string;
    nativeName: string;
  };
  setForm: (
    value: React.SetStateAction<{ code: string; name: string; nativeName: string }>
  ) => void;
  selectedCountryIds: string[];
  toggleCountry: (id: string) => void;
  isSaving: boolean;
  handleSubmit: () => Promise<void>;
};

export function useLanguageForm(): UseLanguageFormResult {
  const { activeLanguage: language } = useInternationalizationUi();
  const { toast } = useToast();
  const saveMutation = useSaveLanguageMutation();

  const [form, setForm] = React.useState({
    code: '',
    name: '',
    nativeName: '',
  });
  const [selectedCountryIds, setSelectedCountryIds] = React.useState<string[]>([]);

  React.useEffect(() => {
    if (language) {
      setForm({
        code: language.code,
        name: language.name,
        nativeName: language.nativeName ?? '',
      });
      setSelectedCountryIds(language.countries?.map((c: { id: string }) => c.id) ?? []);
    } else {
      setForm({ code: '', name: '', nativeName: '' });
      setSelectedCountryIds([]);
    }
  }, [language]);

  const handleSubmit = async (): Promise<void> => {
    if (!form.code.trim() || !form.name.trim()) {
      toast('Language code and name are required.', { variant: 'error' });
      return;
    }

    try {
      const payload: {
        id?: string;
        data: { code: string; name: string; nativeName: string | undefined; countryIds: string[] };
      } = {
        data: {
          code: form.code.trim(),
          name: form.name.trim(),
          nativeName: form.nativeName.trim() || undefined,
          countryIds: selectedCountryIds,
        },
      };
      if (language?.id) {
        payload.id = language.id;
      }

      await saveMutation.mutateAsync(payload);

      toast('Language saved.', { variant: 'success' });
    } catch (err) {
      logClientError(err);
      toast('Failed to save language.', { variant: 'error' });
      throw err;
    }
  };

  const toggleCountry = (id: string): void => {
    setSelectedCountryIds((prev) =>
      prev.includes(id) ? prev.filter((i) => i !== id) : [...prev, id]
    );
  };

  return {
    form,
    setForm,
    selectedCountryIds,
    toggleCountry,
    isSaving: saveMutation.isPending,
    handleSubmit,
  };
}

'use client';

import React, { useMemo, useState, type ReactNode } from 'react';

import {
  useDeleteCountryMutation,
  useDeleteCurrencyMutation,
  useDeleteLanguageMutation,
} from '@/features/internationalization/hooks/useInternationalizationMutations';
import type {
  CountryOption,
  CurrencyOption,
  Language,
} from '@/shared/contracts/internationalization';
import { internalError } from '@/shared/errors/app-error';
import { useCountries, useCurrencies, useLanguages } from '@/shared/hooks/use-i18n-queries';
import { createStrictContext } from '@/shared/lib/react/createStrictContext';
import { useToast } from '@/shared/ui/primitives.public';
import { ConfirmModal } from '@/shared/ui/templates/modals';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';

type ConfirmationConfig = {
  title: string;
  message: string;
  onConfirm: () => void | Promise<void>;
  confirmText?: string;
  isDangerous?: boolean;
};

type ConfirmationState = ConfirmationConfig | null;

export interface InternationalizationDataContextType {
  currencies: CurrencyOption[];
  loadingCurrencies: boolean;
  countries: CountryOption[];
  loadingCountries: boolean;
  filteredCountries: CountryOption[];
  languages: Language[];
  languagesLoading: boolean;
  languagesError: string | null;
}

export interface InternationalizationUiContextType {
  countrySearch: string;
  setCountrySearch: (value: string) => void;
  isLanguageModalOpen: boolean;
  activeLanguage: Language | null;
  isCurrencyModalOpen: boolean;
  activeCurrency: CurrencyOption | null;
  isCountryModalOpen: boolean;
  activeCountry: CountryOption | null;
}

export interface InternationalizationActionsContextType {
  handleOpenLanguageModal: (language?: Language | null) => void;
  handleCloseLanguageModal: () => void;
  handleDeleteLanguage: (language: Language) => Promise<void>;
  handleOpenCurrencyModal: (currency?: CurrencyOption | null) => void;
  handleCloseCurrencyModal: () => void;
  handleDeleteCurrency: (currency: CurrencyOption) => Promise<void>;
  handleOpenCountryModal: (country?: CountryOption | null) => void;
  handleCloseCountryModal: () => void;
  handleDeleteCountry: (country: CountryOption) => Promise<void>;
  confirmAction: (config: ConfirmationConfig) => void;
}

export type InternationalizationContextType = InternationalizationDataContextType &
  InternationalizationUiContextType &
  InternationalizationActionsContextType;

const {
  Context: InternationalizationDataContext,
  useStrictContext: useInternationalizationData,
} = createStrictContext<InternationalizationDataContextType>({
  hookName: 'useInternationalizationData',
  providerName: 'an InternationalizationProvider',
  displayName: 'InternationalizationDataContext',
  errorFactory: internalError,
});

const {
  Context: InternationalizationUiContext,
  useStrictContext: useInternationalizationUi,
} = createStrictContext<InternationalizationUiContextType>({
  hookName: 'useInternationalizationUi',
  providerName: 'an InternationalizationProvider',
  displayName: 'InternationalizationUiContext',
  errorFactory: internalError,
});

const {
  Context: InternationalizationActionsContext,
  useStrictContext: useInternationalizationActions,
} = createStrictContext<InternationalizationActionsContextType>({
  hookName: 'useInternationalizationActions',
  providerName: 'an InternationalizationProvider',
  displayName: 'InternationalizationActionsContext',
  errorFactory: internalError,
});

export {
  useInternationalizationActions,
  useInternationalizationData,
  useInternationalizationUi,
};

export function useInternationalizationContext(): InternationalizationContextType {
  const data = useInternationalizationData();
  const ui = useInternationalizationUi();
  const actions = useInternationalizationActions();
  return {
    ...data,
    ...ui,
    ...actions,
  };
}

export function InternationalizationProvider({
  children,
}: {
  children: ReactNode;
}): React.JSX.Element {
  const { toast } = useToast();

  const { data: currencies = [], isLoading: loadingCurrencies } = useCurrencies();
  const { data: countries = [], isLoading: loadingCountries } = useCountries();
  const {
    data: languages = [],
    isLoading: languagesLoading,
    error: languagesError,
  } = useLanguages();

  const [countrySearch, setCountrySearch] = useState('');
  const [showLanguageModal, setShowLanguageModal] = useState(false);
  const [editingLanguage, setEditingLanguage] = useState<Language | null>(null);
  const [showCurrencyModal, setShowCurrencyModal] = useState(false);
  const [editingCurrency, setEditingCurrency] = useState<CurrencyOption | null>(null);
  const [showCountryModal, setShowCountryModal] = useState(false);
  const [editingCountry, setEditingCountry] = useState<CountryOption | null>(null);
  const [confirmation, setConfirmation] = useState<ConfirmationState>(null);

  const deleteCurrencyMutation = useDeleteCurrencyMutation();
  const deleteCountryMutation = useDeleteCountryMutation();
  const deleteLanguageMutation = useDeleteLanguageMutation();

  const normalizedLanguagesError =
    languagesError instanceof Error ? languagesError.message : languagesError || null;

  const filteredCountries = useMemo(() => {
    const term = countrySearch.trim().toLowerCase();
    if (!term) return countries;
    return countries.filter(
      (country: CountryOption) =>
        country.name.toLowerCase().includes(term) || country.code.toLowerCase().includes(term)
    );
  }, [countries, countrySearch]);

  const confirmAction = (config: ConfirmationConfig): void => {
    setConfirmation(config);
  };

  const handleOpenLanguageModal = (language?: Language | null): void => {
    setEditingLanguage(language ?? null);
    setShowLanguageModal(true);
  };

  const handleDeleteLanguage = async (language: Language): Promise<void> => {
    confirmAction({
      title: 'Delete Language?',
      message: `Are you sure you want to delete ${language.name}? This action cannot be undone.`,
      confirmText: 'Delete',
      isDangerous: true,
      onConfirm: async () => {
        try {
          await deleteLanguageMutation.mutateAsync(language.id);
          toast(`Language ${language.name} deleted.`, { variant: 'success' });
        } catch (error) {
          logClientCatch(error, {
            source: 'InternationalizationContext',
            action: 'deleteLanguage',
            languageId: language.id,
          });
          toast('Failed to delete language.', { variant: 'error' });
        }
      },
    });
  };

  const handleOpenCurrencyModal = (currency?: CurrencyOption | null): void => {
    setEditingCurrency(currency ?? null);
    setShowCurrencyModal(true);
  };

  const handleDeleteCurrency = async (currency: CurrencyOption): Promise<void> => {
    confirmAction({
      title: 'Delete Currency?',
      message: `Are you sure you want to delete ${currency.code}? This action cannot be undone.`,
      confirmText: 'Delete',
      isDangerous: true,
      onConfirm: async () => {
        try {
          await deleteCurrencyMutation.mutateAsync(currency.id);
          toast(`Currency ${currency.code} deleted.`, { variant: 'success' });
        } catch (error) {
          logClientCatch(error, {
            source: 'InternationalizationContext',
            action: 'deleteCurrency',
            currencyId: currency.id,
          });
          toast('Failed to delete currency.', { variant: 'error' });
        }
      },
    });
  };

  const handleOpenCountryModal = (country?: CountryOption | null): void => {
    setEditingCountry(country ?? null);
    setShowCountryModal(true);
  };

  const handleDeleteCountry = async (country: CountryOption): Promise<void> => {
    confirmAction({
      title: 'Delete Country?',
      message: `Are you sure you want to delete ${country.name}? This action cannot be undone.`,
      confirmText: 'Delete',
      isDangerous: true,
      onConfirm: async () => {
        try {
          await deleteCountryMutation.mutateAsync(country.id);
          toast(`Country ${country.name} deleted.`, { variant: 'success' });
        } catch (error) {
          logClientCatch(error, {
            source: 'InternationalizationContext',
            action: 'deleteCountry',
            countryId: country.id,
          });
          toast('Failed to delete country.', { variant: 'error' });
        }
      },
    });
  };

  const dataValue = useMemo<InternationalizationDataContextType>(
    () => ({
      currencies,
      loadingCurrencies,
      countries,
      loadingCountries,
      filteredCountries,
      languages,
      languagesLoading,
      languagesError: normalizedLanguagesError,
    }),
    [
      currencies,
      loadingCurrencies,
      countries,
      loadingCountries,
      filteredCountries,
      languages,
      languagesLoading,
      normalizedLanguagesError,
    ]
  );

  const uiValue = useMemo<InternationalizationUiContextType>(
    () => ({
      countrySearch,
      setCountrySearch,
      isLanguageModalOpen: showLanguageModal,
      activeLanguage: editingLanguage,
      isCurrencyModalOpen: showCurrencyModal,
      activeCurrency: editingCurrency,
      isCountryModalOpen: showCountryModal,
      activeCountry: editingCountry,
    }),
    [
      countrySearch,
      showLanguageModal,
      editingLanguage,
      showCurrencyModal,
      editingCurrency,
      showCountryModal,
      editingCountry,
    ]
  );

  const actionsValue = useMemo<InternationalizationActionsContextType>(
    () => ({
      handleOpenLanguageModal,
      handleCloseLanguageModal: () => setShowLanguageModal(false),
      handleDeleteLanguage,
      handleOpenCurrencyModal,
      handleCloseCurrencyModal: () => setShowCurrencyModal(false),
      handleDeleteCurrency,
      handleOpenCountryModal,
      handleCloseCountryModal: () => setShowCountryModal(false),
      handleDeleteCountry,
      confirmAction,
    }),
    [handleDeleteCountry, handleDeleteCurrency, handleDeleteLanguage]
  );

  return (
    <InternationalizationDataContext.Provider value={dataValue}>
      <InternationalizationUiContext.Provider value={uiValue}>
        <InternationalizationActionsContext.Provider value={actionsValue}>
          {children}
          <ConfirmModal
            isOpen={Boolean(confirmation)}
            onClose={() => setConfirmation(null)}
            title={confirmation?.title ?? ''}
            message={confirmation?.message ?? ''}
            confirmText={confirmation?.confirmText ?? 'Confirm'}
            isDangerous={confirmation?.isDangerous ?? false}
            onConfirm={async () => {
              if (confirmation?.onConfirm) {
                await confirmation.onConfirm();
              }
              setConfirmation(null);
            }}
          />
        </InternationalizationActionsContext.Provider>
      </InternationalizationUiContext.Provider>
    </InternationalizationDataContext.Provider>
  );
}

import 'server-only';

import {
  countryMappings,
  defaultCountries,
  defaultCurrencies,
  defaultLanguages,
} from '@/features/internationalization/lib/internationalizationDefaults';

type CodeRecord = {
  code: string;
  id: string;
};

type InternationalizationSeedTransaction = {
  country: {
    createMany(args: { data: typeof defaultCountries; skipDuplicates: true }): Promise<unknown>;
    findMany(args: { select: { code: true; id: true } }): Promise<CodeRecord[]>;
  };
  countryCurrency: {
    createMany(args: {
      data: Array<{ countryId: string; currencyId: string }>;
      skipDuplicates: true;
    }): Promise<unknown>;
  };
  currency: {
    createMany(args: { data: typeof defaultCurrencies; skipDuplicates: true }): Promise<unknown>;
    findMany(args: { select: { code: true; id: true } }): Promise<CodeRecord[]>;
  };
  language: {
    createMany(args: { data: typeof defaultLanguages; skipDuplicates: true }): Promise<unknown>;
    findMany(args: { select: { code: true; id: true } }): Promise<CodeRecord[]>;
  };
  languageCountry: {
    createMany(args: {
      data: Array<{ countryId: string; languageId: string }>;
      skipDuplicates: true;
    }): Promise<unknown>;
  };
};

export async function ensureInternationalizationDefaults(
  tx: InternationalizationSeedTransaction
): Promise<void> {
  await tx.currency.createMany({
    data: defaultCurrencies,
    skipDuplicates: true,
  });

  await tx.language.createMany({
    data: defaultLanguages,
    skipDuplicates: true,
  });

  await tx.country.createMany({
    data: defaultCountries,
    skipDuplicates: true,
  });

  const [countries, currencies, languages] = await Promise.all([
    tx.country.findMany({ select: { id: true, code: true } }),
    tx.currency.findMany({ select: { id: true, code: true } }),
    tx.language.findMany({ select: { id: true, code: true } }),
  ]);

  const countryByCode = new Map<string, string>(
    countries.map((country: { code: string; id: string }) => [country.code, country.id])
  );

  const currencyByCode = new Map<string, string>(
    currencies.map((currency: { code: string; id: string }) => [currency.code, currency.id])
  );

  const languageByCode = new Map<string, string>(
    languages.map((language: { code: string; id: string }) => [language.code, language.id])
  );

  const countryCurrencyRows: Array<{
    countryId: string;
    currencyId: string;
  }> = [];
  const languageCountryRows: Array<{
    countryId: string;
    languageId: string;
  }> = [];

  for (const mapping of countryMappings) {
    const countryId = countryByCode.get(mapping.countryCode);
    const currencyId = currencyByCode.get(mapping.currencyCode);

    if (countryId && currencyId) {
      countryCurrencyRows.push({ countryId, currencyId });
    }

    for (const languageCode of mapping.languageCodes) {
      const languageId = languageByCode.get(languageCode);
      if (countryId && languageId) {
        languageCountryRows.push({ countryId, languageId });
      }
    }
  }

  if (countryCurrencyRows.length) {
    await tx.countryCurrency.createMany({
      data: countryCurrencyRows,
      skipDuplicates: true,
    });
  }

  if (languageCountryRows.length) {
    await tx.languageCountry.createMany({
      data: languageCountryRows,
      skipDuplicates: true,
    });
  }
}

import { ObjectId, type Document, type AnyBulkWriteOperation, type UpdateFilter, type Db } from 'mongodb';

import { defaultCurrencies } from '@/features/internationalization/server';
import type { CurrencyRecord } from '@/shared/contracts/internationalization';
import type { CurrencyRepository } from '@/shared/contracts/internationalization';
import { notFoundError, internalError } from '@/shared/errors/app-error';
import { getMongoDb } from '@/shared/lib/db/mongo-client';

const COLLECTION = 'currencies';

interface CurrencyDoc extends Document {
  id: string;
  code: string;
  name: string;
  symbol: string | null;
  description?: string | null;
  exchangeRate?: number;
  isDefault?: boolean;
  enabled?: boolean;
  createdAt: Date;
  updatedAt: Date;
}

interface CountryCurrencyDoc extends Document {
  currencyIds?: string[];
  updatedAt?: Date;
}

const PRICE_GROUPS_COLLECTION = 'price_groups';
const COUNTRIES_COLLECTION = 'countries';

const toCurrencyDomain = (doc: CurrencyDoc): CurrencyRecord => ({
  id: doc.id,
  code: doc.code,
  name: doc.name,
  symbol: doc.symbol,
  description: doc.description ?? undefined,
  exchangeRate: doc.exchangeRate ?? undefined,
  isDefault: doc.isDefault ?? false,
  isActive: doc.enabled ?? true,
  createdAt: doc.createdAt.toISOString(),
  updatedAt: doc.updatedAt.toISOString(),
});

const updateRelatedToCurrencyCode = async (
  db: Db,
  id: string,
  nextCode: string,
  now: Date
): Promise<void> => {
  await db
    .collection(PRICE_GROUPS_COLLECTION)
    .updateMany({ currencyId: id }, { $set: { currencyId: nextCode } });

  const countriesCollection = db.collection<CountryCurrencyDoc>(COUNTRIES_COLLECTION);
  const countries = await countriesCollection
    .find({ currencyIds: id }, { projection: { _id: 1, currencyIds: 1 } })
    .toArray();

  const operations: AnyBulkWriteOperation<CountryCurrencyDoc>[] = countries.map((country) => {
    const existingCurrencyIds = Array.isArray(country.currencyIds)
      ? country.currencyIds.filter(
        (currencyId): currencyId is string =>
          typeof currencyId === 'string' && currencyId !== id
      )
      : [];
    return {
      updateOne: {
        filter: { _id: country._id },
        update: {
          $set: {
            currencyIds: Array.from(new Set([...existingCurrencyIds, nextCode])),
            updatedAt: now,
          },
        } satisfies UpdateFilter<CountryCurrencyDoc>,
      },
    };
  });

  if (operations.length > 0) {
    await countriesCollection.bulkWrite(operations, { ordered: false });
  }
};

export const mongoCurrencyRepository: CurrencyRepository = {
  async listCurrencies(filters?: { skip?: number; limit?: number }): Promise<CurrencyRecord[]> {
    const db = await getMongoDb();
    const query = db.collection<CurrencyDoc>(COLLECTION).find({}).sort({ code: 1 });

    if (typeof filters?.skip === 'number') query.skip(filters.skip);
    if (typeof filters?.limit === 'number') query.limit(filters.limit);

    const currencies = await query.toArray();
    return currencies.map(toCurrencyDomain);
  },

  async getCurrencyByCode(code: string): Promise<CurrencyRecord | null> {
    const db = await getMongoDb();
    const doc = await db.collection<CurrencyDoc>(COLLECTION).findOne({ code });
    return doc !== null ? toCurrencyDomain(doc) : null;
  },

  async getCurrencyById(id: string): Promise<CurrencyRecord | null> {
    const db = await getMongoDb();
    const doc = await db.collection<CurrencyDoc>(COLLECTION).findOne({ id });
    return doc !== null ? toCurrencyDomain(doc) : null;
  },

  async createCurrency(data: {
    code: string;
    name: string;
    symbol?: string | null;
  }): Promise<CurrencyRecord> {
    const db = await getMongoDb();
    const now = new Date();
    const doc: CurrencyDoc = {
      _id: new ObjectId(),
      id: data.code,
      code: data.code,
      name: data.name,
      symbol: data.symbol ?? null,
      isDefault: false,
      enabled: true,
      createdAt: now,
      updatedAt: now,
    };
    await db.collection<CurrencyDoc>(COLLECTION).insertOne(doc);
    return toCurrencyDomain(doc);
  },

  async updateCurrency(
    id: string,
    data: { code?: string; name?: string; symbol?: string | null }
  ): Promise<CurrencyRecord> {
    const db = await getMongoDb();
    const collection = db.collection<CurrencyDoc>(COLLECTION);
    const existing = await collection.findOne({ id });
    if (existing === null) throw notFoundError('Currency not found', { id });

    const now = new Date();
    if (data.code !== undefined && data.code !== id) {
      await updateRelatedToCurrencyCode(db, id, data.code, now);
    }

    const nextId = data.code ?? id;
    await collection.updateOne({ id }, {
      $set: {
        ...(data.code !== undefined && { id: data.code, code: data.code }),
        ...(data.name !== undefined && { name: data.name }),
        ...(data.symbol !== undefined && { symbol: data.symbol }),
        updatedAt: now,
      },
    });

    const updated = await collection.findOne({ id: nextId });
    if (updated === null) throw internalError('Failed to update currency', { id: nextId });
    return toCurrencyDomain(updated);
  },

  async deleteCurrency(id: string): Promise<void> {
    const db = await getMongoDb();
    await db.collection(COLLECTION).deleteOne({ id });
  },

  async isCurrencyInUse(id: string): Promise<boolean> {
    const db = await getMongoDb();
    const [priceGroupCount, countryCount] = await Promise.all([
      db.collection(PRICE_GROUPS_COLLECTION).countDocuments({ currencyId: id }),
      db.collection(COUNTRIES_COLLECTION).countDocuments({ currencyIds: id }),
    ]);
    return priceGroupCount > 0 || countryCount > 0;
  },

  async ensureDefaultCurrencies(): Promise<void> {
    const db = await getMongoDb();
    const now = new Date();
    const operations: AnyBulkWriteOperation<CurrencyDoc>[] = defaultCurrencies.map((currency) => ({
      updateOne: {
        filter: { id: currency.code },
        update: {
          $setOnInsert: {
            _id: new ObjectId(),
            id: currency.code,
            code: currency.code,
            name: currency.name,
            symbol: currency.symbol ?? null,
            isDefault: false,
            enabled: true,
            createdAt: now,
          },
          $set: { updatedAt: now },
        },
        upsert: true,
      },
    }));

    if (operations.length > 0) {
      await db.collection<CurrencyDoc>(COLLECTION).bulkWrite(operations, { ordered: false });
    }
  },
};
